import { Workflow, Node } from 'mastra';

const intentDetectionNode = new Node({
  name: 'intent-detection',
  execute: async (input: { emailContent: string; sender: string }) => {
    const llmPrompt = `Classify this email intent: ${input.emailContent}`;
    const result = await llmClient.complete({
      prompt: llmPrompt,
      model: 'gpt-4o'
    });
    return {
      intent: result.intent, // 'reply', 'forward', 'delegate', etc.
      confidence: result.confidence,
      actionRequired: result.actionRequired
    };
  }
});

const emailWorkflow = new Workflow({
  nodes: [intentDetectionNode],
  entryPoint: 'intent-detection'
});

const draftGenerationNode = new Node({
  name: 'draft-generation',
  execute: async (input: { intent: string; attachments: any[]; context: string }) => {
    const attachmentText = await processAttachments(input.attachments);
    const prompt = `Generate professional email draft for ${input.intent}. Attachments: ${attachmentText}. Context: ${input.context}`;

    const draft = await llmClient.complete({
      prompt,
      model: 'gpt-4o',
      temperature: 0.3
    });

    return {
      subject: draft.subject,
      body: draft.body,
      attachments: input.attachments,
      recipients: draft.suggestedRecipients
    };
  }
});

const recipientValidator = {
  name: 'validate_recipients',
  description: 'Validate email recipients for domain and policy compliance',
  execute: async (recipients: string[]) => {
    const validated = await Promise.all(recipients.map(async (email) => {
      const domain = email.split('@')[1];
      const isInternal = await isCompanyDomain(domain);
      const isValidFormat = /^[^@\s]+@[^@\s]+\.[^@\s]+$/.test(email);

      return {
        email,
        valid: isValidFormat && (isInternal || await isApprovedExternal(email)),
        domain,
        isInternal,
        reason: !isValidFormat ? 'invalid_format' : 'ok'
      };
    }));

    return { validated, invalidCount: validated.filter(r => !r.valid).length };
  }
};

const approvalNode = new Node({
  name: 'send-approval',
  execute: async (input: { draft: any; validatedRecipients: any[] }) => {
    const auditRecord = await createAuditRecord(input.draft, input.validatedRecipients);

    // Human approval step
    const approval = await approvalService.requestApproval({
      draft: input.draft,
      recipients: input.validatedRecipients,
      auditId: auditRecord.id,
      urgency: input.draft.urgency || 'normal'
    });

    if (approval.approved) {
      await sendEmail(input.draft);
      return { status: 'sent', messageId: approval.messageId };
    }

    return { status: 'rejected', reason: approval.reason };
  }
});

