import { Vex, Guardrail } from '@vex_dev/sdk';

const vex = new Vex({
  apiKey: process.env.VEX_API_KEY!,
  projectId: 'email-assistant'
});

const workflowValidationGuardrail = new Guardrail({
  name: 'mastra-workflow-validation',
  schema: {
    intent: 'string',
    confidence: 'number',
    actionRequired: 'boolean'
  },
  verifications: ['json_schema']
});

// Mastra pipeline middleware
const mastraMiddleware = async (input: any, next: () => Promise<any>) => {
  const result = await next();

  const verified = await vex.verify({
    guardrail: workflowValidationGuardrail,
    input: input,
    output: result
  });

  if (!verified.passed) {
    throw new Error(`Workflow validation failed: ${verified.issues}`);
  }

  return result;
};

const piiGuardrail = new Guardrail({
  name: 'email-pii-filter',
  verifications: ['pii_detection'],
  actions: {
    redact: true,
    block: ['ssn', 'passport', 'credit_card']
  }
});

const draftPIIMiddleware = async (draft: any, next: () => Promise<any>) => {
  const piiCheck = await vex.verify({
    guardrail: piiGuardrail,
    input: { content: draft.body },
    context: { workflow: 'email-draft' }
  });

  if (piiCheck.detected.length > 0) {
    draft.body = piiCheck.redactedContent;
    draft.piiAlert = true;
    await logSecurityEvent('PII_DETECTED', piiCheck.detected);
  }

  return next();
};

const memoryGuardrail = new Guardrail({
  name: 'memory-freshness',
  verifications: ['timestamp_check'],
  rules: {
    maxAgeHours: 24,
    relevanceThreshold: 0.8
  }
});

const memoryMiddleware = async (context: any, next: () => Promise<any>) => {
  const freshnessCheck = await vex.verify({
    guardrail: memoryGuardrail,
    input: context,
    metadata: { source: 'mastra-knowledge-base' }
  });

  if (!freshnessCheck.passed) {
    console.warn('Stale context detected, fetching fresh data');
    context = await refreshConversationContext(context.threadId);
  }

  return next();
};
